import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"更新ログ: バージョン履歴 | Plannotator","description":"Plannotator のバージョン履歴と新機能を学びます。メジャーアップデート、バグ修正、パフォーマンス改善を確認し、コードレビュー、画像アノテーション、Obsidian 統合などの新機能を把握します。","frontmatter":{"title":"更新ログ: バージョン履歴 | Plannotator","sidebarTitle":"新機能を確認","subtitle":"更新ログ: バージョン履歴 | Plannotator","description":"Plannotator のバージョン履歴と新機能を学びます。メジャーアップデート、バグ修正、パフォーマンス改善を確認し、コードレビュー、画像アノテーション、Obsidian 統合などの新機能を把握します。","tags":["更新ログ","バージョン履歴","新機能","バグ修正"],"order":1},"headers":[],"relativePath":"ja/backnotprop/plannotator/changelog/release-notes/index.md","filePath":"ja/backnotprop/plannotator/changelog/release-notes/index.md"}'),n={name:"ja/backnotprop/plannotator/changelog/release-notes/index.md"};function l(i,t,s,p,g,c){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="更新ログ-plannotator-バージョン履歴と新機能" tabindex="-1">更新ログ：Plannotator バージョン履歴と新機能 <a class="header-anchor" href="#更新ログ-plannotator-バージョン履歴と新機能" aria-label="Permalink to &quot;更新ログ：Plannotator バージョン履歴と新機能&quot;">​</a></h1><h2 id="学習目標" tabindex="-1">学習目標 <a class="header-anchor" href="#学習目標" aria-label="Permalink to &quot;学習目標&quot;">​</a></h2><ul><li>✅ Plannotator のバージョン履歴と新機能を理解する</li><li>✅ 各バージョンのメジャーアップデートと改善点を把握する</li><li>✅ バグ修正とパフォーマンス最適化を理解する</li></ul><hr><h2 id="最新バージョン" tabindex="-1">最新バージョン <a class="header-anchor" href="#最新バージョン" aria-label="Permalink to &quot;最新バージョン&quot;">​</a></h2><h3 id="v0-6-7-2026-01-24" tabindex="-1">v0.6.7 (2026-01-24) <a class="header-anchor" href="#v0-6-7-2026-01-24" aria-label="Permalink to &quot;v0.6.7 (2026-01-24)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>Comment mode</strong>：プラン内で直接コメントを入力できる Comment モードを追加</li><li><strong>Type-to-comment shortcut</strong>：コメント内容を直接入力するためのショートカットキーを追加</li></ul><p><strong>改善</strong>：</p><ul><li>OpenCode プラグインの sub-agent blocking 問題を修正</li><li>prompt injection セキュリティ脆弱性（CVE）を修正</li><li>OpenCode での agent switching のインテリジェント検出を改善</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Comment mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L23-L42" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li><li>Type-to-comment: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationToolbar.tsx#L80-L100" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationToolbar.tsx</code></a></li></ul><hr><h3 id="v0-6-6-2026-01-20" tabindex="-1">v0.6.6 (2026-01-20) <a class="header-anchor" href="#v0-6-6-2026-01-20" aria-label="Permalink to &quot;v0.6.6 (2026-01-20)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>OpenCode プラグインの CVE セキュリティ脆弱性を修正</li><li>prompt injection を防ぐための sub-agent blocking 問題を修正</li><li>agent switching のインテリジェント検出ロジックを改善</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>OpenCode plugin: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L245-L280" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li><li>Agent switching: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/agentSwitch.ts#L1-L50" target="_blank" rel="noreferrer"><code>packages/ui/utils/agentSwitch.ts</code></a></li></ul><hr><h3 id="v0-6-5-2026-01-15" tabindex="-1">v0.6.5 (2026-01-15) <a class="header-anchor" href="#v0-6-5-2026-01-15" aria-label="Permalink to &quot;v0.6.5 (2026-01-15)&quot;">​</a></h3><p><strong>改善</strong>：</p><ul><li><strong>Hook timeout の増加</strong>：長時間実行される AI プランに対応するため、hook timeout をデフォルト値から 4 日に増加</li><li><strong>Copy 機能の修正</strong>：コピー操作での改行を維持</li><li><strong>Cmd+C ショートカットキーの追加</strong>：Cmd+C ショートカットキーを追加</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Hook timeout: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L44-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></li><li>Copy newlines: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Viewer.tsx#L150-L170" target="_blank" rel="noreferrer"><code>packages/ui/components/Viewer.tsx</code></a></li></ul><hr><h3 id="v0-6-4-2026-01-10" tabindex="-1">v0.6.4 (2026-01-10) <a class="header-anchor" href="#v0-6-4-2026-01-10" aria-label="Permalink to &quot;v0.6.4 (2026-01-10)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>Cmd+Enter ショートカットキー</strong>：Cmd+Enter（Windows: Ctrl+Enter）で承認やフィードバックを送信できるように</li></ul><p><strong>改善</strong>：</p><ul><li>キーボード操作のエクスペリエンスを最適化</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Keyboard shortcuts: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/AnnotationPanel.tsx#L323" target="_blank" rel="noreferrer"><code>packages/ui/components/AnnotationPanel.tsx</code></a> （Cmd+Enter ショートカット機能は各コンポーネントで直接実装されています）</li></ul><hr><h3 id="v0-6-3-2026-01-05" tabindex="-1">v0.6.3 (2026-01-05) <a class="header-anchor" href="#v0-6-3-2026-01-05" aria-label="Permalink to &quot;v0.6.3 (2026-01-05)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>skip-title-generation-prompt の問題を修正</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Skip title: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L67-L71" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-2-2026-01-01" tabindex="-1">v0.6.2 (2026-01-01) <a class="header-anchor" href="#v0-6-2-2026-01-01" aria-label="Permalink to &quot;v0.6.2 (2026-01-01)&quot;">​</a></h3><p><strong>修正</strong>：</p><ul><li>OpenCode プラグインで HTML ファイルが npm パッケージに含まれていない問題を修正</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>OpenCode plugin build: <a href="https://github.com/backnotprop/plannotator/blob/main/apps/opencode-plugin/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/opencode-plugin/index.ts</code></a></li></ul><hr><h3 id="v0-6-1-2025-12-20" tabindex="-1">v0.6.1 (2025-12-20) <a class="header-anchor" href="#v0-6-1-2025-12-20" aria-label="Permalink to &quot;v0.6.1 (2025-12-20)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>Bear 統合</strong>：承認されたプランを Bear ノートアプリに自動保存</li></ul><p><strong>改善</strong>：</p><ul><li>Obsidian 統合のタグ生成ロジックを改善</li><li>Obsidian vault 検出メカニズムを最適化</li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Bear 統合: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L280" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 統合: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li></ul><hr><h2 id="メジャー機能リリース" tabindex="-1">メジャー機能リリース <a class="header-anchor" href="#メジャー機能リリース" aria-label="Permalink to &quot;メジャー機能リリース&quot;">​</a></h2><h3 id="code-review-機能-2026-01" tabindex="-1">Code Review 機能 (2026-01) <a class="header-anchor" href="#code-review-機能-2026-01" aria-label="Permalink to &quot;Code Review 機能 (2026-01)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>コードレビューツール</strong>：<code>/plannotator-review</code> コマンドを実行して、Git diff を視覚的にレビュー</li><li><strong>行レベルコメント</strong>：行番号をクリックしてコード範囲を選択し、comment/suggestion/concern タイプのコメントを追加</li><li><strong>複数の diff ビュー</strong>：uncommitted/staged/last-commit/branch など、異なる diff タイプを切り替え可能</li><li><strong>Agent 統合</strong>：構造化されたフィードバックを AI agent に送信し、自動応答をサポート</li></ul><p><strong>使用方法</strong>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># プロジェクトディレクトリで実行</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>関連チュートリアル</strong>：</p><ul><li><a href="./../../platforms/code-review-basics/">コードレビューの基礎</a></li><li><a href="./../../platforms/code-review-annotations/">コードコメントの追加</a></li><li><a href="./../../platforms/code-review-diff-types/">Diff ビューの切り替え</a></li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Code review server: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></li><li>Code review UI: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></li><li>Git diff ツール: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></li></ul><hr><h3 id="画像アノテーション機能-2026-01" tabindex="-1">画像アノテーション機能 (2026-01) <a class="header-anchor" href="#画像アノテーション機能-2026-01" aria-label="Permalink to &quot;画像アノテーション機能 (2026-01)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>画像アップロード</strong>：プランやコードレビューに画像添付をアップロード</li><li><strong>アノテーションツール</strong>：ペン、矢印、円の 3 種類のアノテーションツールを提供</li><li><strong>視覚的アノテーション</strong>：画像上で直接アノテーションを行い、レビューフィードバックの効果を強化</li></ul><p><strong>関連チュートリアル</strong>：</p><ul><li><a href="./../../platforms/plan-review-images/">画像アノテーションの追加</a></li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Image annotator: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/ImageAnnotator/index.tsx" target="_blank" rel="noreferrer"><code>packages/ui/components/ImageAnnotator/index.tsx</code></a></li><li>Upload API: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L160-L180" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></li></ul><hr><h3 id="obsidian-統合-2025-12" tabindex="-1">Obsidian 統合 (2025-12) <a class="header-anchor" href="#obsidian-統合-2025-12" aria-label="Permalink to &quot;Obsidian 統合 (2025-12)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>Vault の自動検出</strong>：Obsidian vault 設定ファイルパスを自動検出</li><li><strong>プランの自動保存</strong>：承認されたプランを Obsidian に自動保存</li><li><strong>Frontmatter の自動生成</strong>：created、source、tags などの frontmatter を自動含める</li><li><strong>インテリジェントタグ抽出</strong>：プランの内容からキーワードを抽出してタグとして設定</li></ul><p><strong>設定方法</strong>： 追加の設定は不要です。Plannotator は Obsidian のインストールパスを自動検出します。</p><p><strong>関連チュートリアル</strong>：</p><ul><li><a href="./../../advanced/obsidian-integration/">Obsidian 統合</a></li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Obsidian 検出: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L136-L145" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Obsidian 保存: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L220" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></li><li>Frontmatter 生成: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L50-L80" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></li></ul><hr><h3 id="url-共有機能-2025-11" tabindex="-1">URL 共有機能 (2025-11) <a class="header-anchor" href="#url-共有機能-2025-11" aria-label="Permalink to &quot;URL 共有機能 (2025-11)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>バックエンドなしの共有</strong>：プランとコメントを URL hash に圧縮して、バックエンドサーバーなしで共有</li><li><strong>ワンクリック共有</strong>：Export → Share as URL をクリックして共有リンクを生成</li><li><strong>読み取り専用モード</strong>：共同作業者が URL を開いて閲覧できますが、決定を送信することはできません</li></ul><p><strong>技術実装</strong>：</p><ul><li>Deflate 圧縮アルゴリズムを使用</li><li>Base64 エンコード + URL 安全文字の置換</li><li>最大約 7 タブの payload をサポート</li></ul><p><strong>関連チュートリアル</strong>：</p><ul><li><a href="./../../advanced/url-sharing/">URL 共有</a></li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Sharing utils: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/sharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/utils/sharing.ts</code></a></li><li>Share hook: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/hooks/useSharing.ts" target="_blank" rel="noreferrer"><code>packages/ui/hooks/useSharing.ts</code></a></li></ul><hr><h3 id="リモート-devcontainer-モード-2025-10" tabindex="-1">リモート/Devcontainer モード (2025-10) <a class="header-anchor" href="#リモート-devcontainer-モード-2025-10" aria-label="Permalink to &quot;リモート/Devcontainer モード (2025-10)&quot;">​</a></h3><p><strong>新機能</strong>：</p><ul><li><strong>リモートモードサポート</strong>：SSH、devcontainer、WSL などのリモート環境で Plannotator を使用</li><li><strong>固定ポート</strong>：環境変数で固定ポートを設定</li><li><strong>ポート転送</strong>：ユーザーがブラウザを手動で開くための URL を自動出力</li><li><strong>ブラウザ制御</strong>：<code>PLANNOTATOR_BROWSER</code> 環境変数でブラウザを開くかどうかを制御</li></ul><p><strong>環境変数</strong>：</p><ul><li><code>PLANNOTATOR_REMOTE=1</code>：リモートモードを有効化</li><li><code>PLANNOTATOR_PORT=3000</code>：固定ポートを設定</li><li><code>PLANNOTATOR_BROWSER=disabled</code>：ブラウザの自動起動を無効化</li></ul><p><strong>関連チュートリアル</strong>：</p><ul><li><a href="./../../advanced/remote-mode/">リモート/Devcontainer モード</a></li><li><a href="./../../advanced/environment-variables/">環境変数の設定</a></li></ul><p><strong>ソースコード参照</strong>：</p><ul><li>Remote mode: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/remote.ts" target="_blank" rel="noreferrer"><code>packages/server/remote.ts</code></a></li><li>Browser control: <a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/browser.ts" target="_blank" rel="noreferrer"><code>packages/server/browser.ts</code></a></li></ul><hr><h2 id="バージョン互換性" tabindex="-1">バージョン互換性 <a class="header-anchor" href="#バージョン互換性" aria-label="Permalink to &quot;バージョン互換性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plannotator バージョン</th><th>Claude Code</th><th>OpenCode</th><th>Bun 最低バージョン</th></tr></thead><tbody><tr><td>v0.6.x</td><td>2.1.7+</td><td>1.0+</td><td>1.0+</td></tr><tr><td>v0.5.x</td><td>2.1.0+</td><td>0.9+</td><td>0.7+</td></tr></tbody></table><p><strong>アップグレードの推奨</strong>：</p><ul><li>最新の機能とセキュリティ修正を取得するため、Plannotator を最新バージョンに保ってください</li><li>Claude Code と OpenCode も最新バージョンに保つことが推奨されます</li></ul><hr><h2 id="ライセンスの変更" tabindex="-1">ライセンスの変更 <a class="header-anchor" href="#ライセンスの変更" aria-label="Permalink to &quot;ライセンスの変更&quot;">​</a></h2><p><strong>現在のバージョン（v0.6.7+）</strong>：Business Source License 1.1 (BSL-1.1)</p><p><strong>ライセンス詳細</strong>：</p><ul><li>許可：個人利用、内部商用利用</li><li>制限：ホスティングサービス、SaaS 製品の提供</li><li>詳細は <a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer">LICENSE</a> を参照</li></ul><hr><h2 id="フィードバックとサポート" tabindex="-1">フィードバックとサポート <a class="header-anchor" href="#フィードバックとサポート" aria-label="Permalink to &quot;フィードバックとサポート&quot;">​</a></h2><p><strong>問題の報告</strong>：</p><ul><li>GitHub Issues: <a href="https://github.com/backnotprop/plannotator/issues" target="_blank" rel="noreferrer">https://github.com/backnotprop/plannotator/issues</a></li></ul><p><strong>機能の提案</strong>：</p><ul><li>GitHub Issues で feature request を送信</li></ul><p><strong>セキュリティ脆弱性</strong>：</p><ul><li>セキュリティ脆弱性はプライベートなチャンネルを通じて報告してください</li></ul><hr><h2 id="次のレッスンの予告" tabindex="-1">次のレッスンの予告 <a class="header-anchor" href="#次のレッスンの予告" aria-label="Permalink to &quot;次のレッスンの予告&quot;">​</a></h2><blockquote><p>Plannotator のバージョン履歴と新機能を理解しました。</p><p>次は：</p><ul><li><a href="./../../start/getting-started/">クイックスタート</a> に戻ってインストールと使用方法を学ぶ</li><li><a href="./../../faq/common-problems/">よくある問題</a> を見て使用中の問題を解決する</li><li><a href="./../../appendix/api-reference/">API リファレンス</a> を読んですべての API エンドポイントを理解する</li></ul></blockquote>`,121)])])}const u=a(n,[["render",l]]);export{h as __pageData,u as default};
